<?php
namespace App\Filament\Pages;
use App\Models\PaymentProviderSecret;use App\Services\Finance\{PaymentProviderManager,PaymentProviderSecretService};use Filament\Notifications\Notification;use Illuminate\Contracts\Support\Htmlable;
class PaymentProviderSettings extends AdminOsModulePage{public string $secretKey='client_id';public string $secretValue='';public string $forgetReason='';protected static string|\BackedEnum|null $navigationIcon='heroicon-o-credit-card';protected static ?string $navigationLabel='Provider Settings';protected static string|\UnitEnum|null $navigationGroup='Finance';protected static ?int $navigationSort=30;protected static ?string $title='Payment Provider Settings';protected string $view='filament.pages.payment-provider-settings';public function getModuleKey():string{return 'finance';}public function getHeading():string|Htmlable{return '';}public static function canAccess():bool{return auth()->user()?->can('admin.finance.provider_settings')||auth()->user()?->can('admin.system.manage')||auth()->user()?->can('admin.finance.manage')??false;}public function setSecret():void{$this->validate(['secretKey'=>'required|in:client_id,client_secret,subscription_key,webhook_secret','secretValue'=>'required|string|min:8|max:4096']);app(PaymentProviderSecretService::class)->setSecret('vipps_mobilepay','sandbox',$this->secretKey,$this->secretValue,auth()->user());$this->secretValue='';Notification::make()->title('Encrypted secret stored. Plaintext is no longer displayed.')->success()->send();}public function forgetSecret():void{$this->validate(['forgetReason'=>'required|string|min:5|max:500']);app(PaymentProviderSecretService::class)->forgetSecret('vipps_mobilepay','sandbox',$this->secretKey,auth()->user());$this->forgetReason='';Notification::make()->title('Secret removed from active configuration.')->warning()->send();}public function getViewData():array{$manager=app(PaymentProviderManager::class);$status=$manager->status();return ['status'=>$status,'secrets'=>PaymentProviderSecret::where('provider','vipps_mobilepay')->where('environment','sandbox')->get()->keyBy('key_name'),'financeUrl'=>route('filament.admin.pages.finance-control'),'securityUrl'=>route('filament.admin.pages.system-security'),'webhookUrl'=>url('/api/payments/vipps-mobilepay/webhook')];}}